// Modified Code2 - Split Weekly/Aggregated and Regular Items
const inputItems = $input.all();
const aggregatedItems = [];
const regularItems = [];

// Keywords that indicate aggregated/compiled content
const weeklyPatterns = [
    /this week'?s/i,
    /weekly/i,
    /roundup/i,
    /stories from/i,
    /through (july|june|may|april|march|february|january|december|jan|feb|mar|apr|jun|jul|aug|sep|oct|nov|dec)/i,
    /through \w+ \d+/i,
    /curation/i,
    /digest/i,
    /compilation/i,
    /wrap.?up/i,
    /tech stories/i,
    /awesome.*stories/i,
    /around the web/i,
    /newsletter/i,
    /daily.*stories/i,
    /morning.*brief/i,
    /evening.*update/i
];

// Check each item and categorize
inputItems.forEach((item, index) => {
    const data = item.json;
    const title = (data.title || '').toLowerCase();
    const creator = (data.creator || data['dc:creator'] || '').toLowerCase();

    // Check if title matches weekly/aggregated patterns
    const isAggregated = weeklyPatterns.some(pattern => pattern.test(title));

    // Additional checks for common aggregator creators
    const isStaffCreated = /staff|editorial|team/i.test(creator);

    if (isAggregated || isStaffCreated) {
        // This is weekly/aggregated content
        aggregatedItems.push({
            json: {
                ...data,
                originalIndex: index,
                detectedAs: 'aggregated_content',
                matchReason: isAggregated ? 'title_pattern' : 'staff_creator',
                itemType: 'weekly'
            }
        });
    } else {
        // This is regular content - format for Edit Fields1
        regularItems.push({
            json: {
                title: data.title || '',
                link: data.link || '',
                contentSnippet: data.contentSnippet || '',
                pubDate: data.pubDate || '',
                source: data.source || '', // You might need to adjust this based on your data structure
                originalIndex: index,
                itemType: 'regular'
            }
        });
    }
});

// Return both arrays - n8n will handle multiple outputs
return [
    ...aggregatedItems,  // Weekly items (will go to Switch1)
    ...regularItems      // Regular items (will go to Edit Fields1)
];

