// Code Node to Extract News Data from OpenAI Response
// Place this after your OpenAI node and before Airtable

// Get the OpenAI response content - handle multiple items
let aiResponse = $json.message.content;
let inputItems = $input.all(); // Get all input items

// Function to clean the response
function cleanResponse(response) {
  // Remove code blocks if present
  response = response.replace(/```json\n?/g, '').replace(/\n?```/g, '');

  // Remove escape characters
  response = response.replace(/\\n/g, ' ').replace(/\\"/g, '"');

  // Remove actual newlines and extra spaces
  response = response.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();

  return response;
}

// Function to extract field using regex
function extractField(text, fieldName) {
  const regex = new RegExp(`"${fieldName}"\\s*:\\s*"([^"]*)"`, 'i');
  const match = text.match(regex);
  return match ? match[1] : '';
}

// Function to extract numeric field
function extractNumericField(text, fieldName) {
  const regex = new RegExp(`"${fieldName}"\\s*:\\s*(\\d+)`, 'i');
  const match = text.match(regex);
  return match ? parseInt(match[1]) : 0;
}

// Process each input item
let results = [];

// If there are multiple input items, process each one
if (inputItems && inputItems.length > 0) {
  inputItems.forEach((item, index) => {
    try {
      // Get the AI response for this item
      let currentResponse = item.json.message ? item.json.message.content : aiResponse;

      // Clean the AI response
      const cleanedResponse = cleanResponse(currentResponse);

      // Try to parse as JSON first
      let extractedData;
      try {
        const parsedJson = JSON.parse(cleanedResponse);
        extractedData = {
          title: parsedJson.title || parsedJson.article?.title || '',
          summary: parsedJson.summary || parsedJson.article?.summary || '',
          link: parsedJson.link || parsedJson.article?.link || '',
          source: parsedJson.source || parsedJson.article?.source || '',
          date: parsedJson.date || parsedJson.article?.date || '',
          importance: parsedJson.importance || parsedJson.analysis?.importance || 0,
          virality: parsedJson.virality || parsedJson.analysis?.virality || 0
        };
      } catch (jsonError) {
        // If JSON parsing fails, use regex extraction
        extractedData = {
          title: extractField(cleanedResponse, 'title'),
          summary: extractField(cleanedResponse, 'summary'),
          link: extractField(cleanedResponse, 'link'),
          source: extractField(cleanedResponse, 'source'),
          date: extractField(cleanedResponse, 'date'),
          importance: extractNumericField(cleanedResponse, 'importance'),
          virality: extractNumericField(cleanedResponse, 'virality')
        };
      }

      // Clean up any remaining escape characters in text fields
      Object.keys(extractedData).forEach(key => {
        if (typeof extractedData[key] === 'string') {
          extractedData[key] = extractedData[key]
            .replace(/\\n/g, ' ')
            .replace(/\\t/g, ' ')
            .replace(/\s+/g, ' ')
            .trim();
        }
      });

      // Add to results
      results.push({
        json: {
          title: extractedData.title,
          summary: extractedData.summary,
          link: extractedData.link,
          source: extractedData.source,
          date: extractedData.date,
          importance: extractedData.importance,
          virality: extractedData.virality,

        }
      });

    } catch (error) {
      // If extraction fails for this item, add error object
      results.push({
        json: {
          error: `Failed to extract data for item ${index}: ${error.message}`,
          raw_response: item.json.message ? item.json.message.content : aiResponse,
          title: '',
          summary: '',
          link: '',
          source: '',
          date: '',
          importance: 0,
          virality: 0
        }
      });
    }
  });
} else {
  // Fallback to single item processing
  try {
    const cleanedResponse = cleanResponse(aiResponse);

    let extractedData;
    try {
      const parsedJson = JSON.parse(cleanedResponse);
      extractedData = {
        title: parsedJson.title || parsedJson.article?.title || '',
        summary: parsedJson.summary || parsedJson.article?.summary || '',
        link: parsedJson.link || parsedJson.article?.link || '',
        source: parsedJson.source || parsedJson.article?.source || '',
        date: parsedJson.date || parsedJson.article?.date || '',
        importance: parsedJson.importance || parsedJson.analysis?.importance || 0,
        virality: parsedJson.virality || parsedJson.analysis?.virality || 0
      };
    } catch (jsonError) {
      extractedData = {
        title: extractField(cleanedResponse, 'title'),
        summary: extractField(cleanedResponse, 'summary'),
        link: extractField(cleanedResponse, 'link'),
        source: extractField(cleanedResponse, 'source'),
        date: extractField(cleanedResponse, 'date'),
        importance: extractNumericField(cleanedResponse, 'importance'),
        virality: extractNumericField(cleanedResponse, 'virality')
      };
    }

    Object.keys(extractedData).forEach(key => {
      if (typeof extractedData[key] === 'string') {
        extractedData[key] = extractedData[key]
          .replace(/\\n/g, ' ')
          .replace(/\\t/g, ' ')
          .replace(/\s+/g, ' ')
          .trim();
      }
    });

    results.push({
      json: {
        title: extractedData.title,
        summary: extractedData.summary,
        link: extractedData.link,
        source: extractedData.source,
        date: extractedData.date,
        importance: extractedData.importance,
        virality: extractedData.virality
      }
    });

  } catch (error) {
    results.push({
      json: {
        error: `Failed to extract data: ${error.message}`,
        raw_response: aiResponse,
        title: '',
        summary: '',
        link: '',
        source: '',
        date: '',
        importance: 0,
        virality: 0
      }
    });
  }
}

return results;
